            color: #fff;
            padding: 15px;
            text-align: center;
            border-radius: 5px 5px 0 0;
        }
       .content {
            padding: 20px;
        }
       .footer {
            background-color: #f1f1f1;
            color: #333;
            text-align: center;
            padding: 10px;
            border-radius: 0 0 5px 5px;
        }
       .button {
            display: inline-block;
            padding: 10px 20px;
            background-color: #4CAF50;
